import{_ as a,c as o,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"ライセンス: BSL条項の説明 | Plannotator","description":"Plannotator の Business Source License 1.1 (BSL) ライセンス条項と商用利用制限について学びます。許可される使用シナリオ、将来の変更計画、2030年に Apache 2.0 へ移行するタイムラインを理解しましょう。","frontmatter":{"title":"ライセンス: BSL条項の説明 | Plannotator","sidebarTitle":"商用利用ルールを理解する","subtitle":"ライセンス: BSL条項の説明","description":"Plannotator の Business Source License 1.1 (BSL) ライセンス条項と商用利用制限について学びます。許可される使用シナリオ、将来の変更計画、2030年に Apache 2.0 へ移行するタイムラインを理解しましょう。","tags":["ライセンス","BSL-1.1","商用利用"],"prerequisite":[],"order":3},"headers":[],"relativePath":"ja/backnotprop/plannotator/appendix/license/index.md","filePath":"ja/backnotprop/plannotator/appendix/license/index.md"}'),n={name:"ja/backnotprop/plannotator/appendix/license/index.md"};function e(i,t,s,d,h,p){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="plannotator-ライセンス説明" tabindex="-1">Plannotator ライセンス説明 <a class="header-anchor" href="#plannotator-ライセンス説明" aria-label="Permalink to &quot;Plannotator ライセンス説明&quot;">​</a></h1><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>Plannotator が使用するライセンスの種類とコア条項を理解する</li><li>どの使用シナリオが許可され、どれが制限されるかを明確にする</li><li>ライセンスの将来の変更タイムラインを把握する</li><li>商用ライセンスの取得方法やライセンサーへの連絡方法を知る</li></ul><h2 id="今知っておくべきこと" tabindex="-1">今知っておくべきこと <a class="header-anchor" href="#今知っておくべきこと" aria-label="Permalink to &quot;今知っておくべきこと&quot;">​</a></h2><p>Plannotator は <strong>Business Source License 1.1 (BSL)</strong> をオープンソースライセンスとして採用しています。これは、商業的価値を保護しながら、最終的にプロジェクトを完全にオープンソース化することを目的とした特殊なライセンスです。</p><h2 id="コア条項" tabindex="-1">コア条項 <a class="header-anchor" href="#コア条項" aria-label="Permalink to &quot;コア条項&quot;">​</a></h2><h3 id="ライセンスの種類" tabindex="-1">ライセンスの種類 <a class="header-anchor" href="#ライセンスの種類" aria-label="Permalink to &quot;ライセンスの種類&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td><strong>ライセンス名</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>著作権者</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>対象プロジェクト</strong></td><td>plannotator</td></tr><tr><td><strong>変更日</strong></td><td>2030-01-01</td></tr><tr><td><strong>変更後のライセンス</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">BSL とは？</p><p>Business Source License は MariaDB が開発した特殊なライセンスです。短期的には特定の商用利用を制限しますが、特定の日付以降にソフトウェアを完全なオープンソースライセンス（Apache 2.0 など）に変換することを約束しています。このモデルにより、オープンソースプロジェクトは商業化の過程で持続可能な収益を得ながら、長期的にはコミュニティに開放されることが保証されます。</p></div><h3 id="許可される使用方法" tabindex="-1">許可される使用方法 <a class="header-anchor" href="#許可される使用方法" aria-label="Permalink to &quot;許可される使用方法&quot;">​</a></h3><p>BSL 1.1 の条項に基づき、以下のことが可能です：</p><ul><li><p>✅ <strong>複製、修正、派生作品の作成</strong></p><ul><li>Plannotator をベースに二次開発が可能</li><li>ニーズに合わせてソースコードを修正可能</li></ul></li><li><p>✅ <strong>再配布</strong></p><ul><li>オリジナルまたは修正版の配布が可能</li><li>元のライセンス表示を保持する必要あり</li></ul></li><li><p>✅ <strong>非本番環境での使用</strong></p><ul><li>社内開発、テスト、評価</li><li>個人学習と研究</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">個人および企業内部での幅広い使用</p><p>BSL の「非本番環境での使用」の定義は広範で、個人および企業内部のさまざまなシナリオを含みます。あなたとチームメンバー（独立請負業者を含む）は、開発、テスト、デプロイのために Plannotator を自由に使用できます。</p></div><h3 id="使用制限-重要" tabindex="-1">使用制限（重要！） <a class="header-anchor" href="#使用制限-重要" aria-label="Permalink to &quot;使用制限（重要！）&quot;">​</a></h3><p><strong>コア制限</strong>：Plannotator を <strong>計画、コンテキスト、または承認サービス（Planning, Context, or Approval Service）</strong> に使用することはできません。</p><h4 id="「計画、コンテキスト、または承認サービス」とは" tabindex="-1">「計画、コンテキスト、または承認サービス」とは？ <a class="header-anchor" href="#「計画、コンテキスト、または承認サービス」とは" aria-label="Permalink to &quot;「計画、コンテキスト、または承認サービス」とは？&quot;">​</a></h4><p><strong>第三者</strong>（従業員および独立請負業者を除く）が直接的または間接的な操作を通じて Plannotator の機能にアクセスできる商用製品は、制限対象のサービスに該当します。具体的には以下を含みますが、これらに限定されません：</p><ul><li><p><strong>クラウドサービスプロバイダー</strong></p><ul><li>SaaS プラットフォームがサービスの一部として Plannotator 機能を提供</li><li>ホスティングサービスプロバイダーが顧客やサブスクライバーに Plannotator を提供</li></ul></li><li><p><strong>インフラストラクチャサービス</strong></p><ul><li>データセンターサービスプロバイダー</li><li>クラウドコンピューティングプラットフォームプロバイダー</li></ul></li><li><p><strong>類似サービスの第三者</strong></p><ul><li>上記の事業体およびその関連会社が提供するあらゆるサービスを含む</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">商用利用に関する警告</p><p>Plannotator を商用サービスの一部として第三者に提供する予定がある場合は、事前に商用ライセンスを取得する必要があります。この条項に違反すると、現在およびすべてのバージョンの Plannotator の使用権が自動的に終了します。</p></div><h2 id="ライセンス変更タイムライン" tabindex="-1">ライセンス変更タイムライン <a class="header-anchor" href="#ライセンス変更タイムライン" aria-label="Permalink to &quot;ライセンス変更タイムライン&quot;">​</a></h2><table tabindex="0"><thead><tr><th>時期</th><th>ライセンスの種類</th><th>説明</th></tr></thead><tbody><tr><td><strong>現在 - 2030-01-01</strong></td><td>BSL 1.1</td><td>制限付きオープンソースライセンス</td></tr><tr><td><strong>2030-01-01 以降</strong></td><td>Apache 2.0</td><td>完全オープンソース、商用制限なし</td></tr></tbody></table><h3 id="変更後に何が起こるか" tabindex="-1">変更後に何が起こるか？ <a class="header-anchor" href="#変更後に何が起こるか" aria-label="Permalink to &quot;変更後に何が起こるか？&quot;">​</a></h3><p>2030年1月1日から、Plannotator は自動的に <strong>Apache License 2.0</strong> に変換されます。これは以下を意味します：</p><ul><li>✅ すべての商用制限が解除される</li><li>✅ あらゆる商用目的に自由に使用可能</li><li>✅ 任意の SaaS サービスに統合可能</li><li>✅ 寛容なオープンソースライセンス基準に準拠</li></ul><h2 id="商用ライセンス" tabindex="-1">商用ライセンス <a class="header-anchor" href="#商用ライセンス" aria-label="Permalink to &quot;商用ライセンス&quot;">​</a></h2><p>BSL の制限に従わずに Plannotator を使用する必要がある場合（例：計画、コンテキスト、または承認サービス用）、以下の方法があります：</p><ol><li><p><strong>商用ライセンスの購入</strong></p><ul><li>backnotprop またはその認定販売代理店から購入</li><li>BSL 制限のない使用権を取得</li></ul></li><li><p><strong>ライセンサーへの連絡</strong></p><ul><li>メール送信先：backnotprop</li><li>使用シナリオと要件を説明</li></ul></li></ol><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><h3 id="社内で-plannotator-を使用できますか" tabindex="-1">社内で Plannotator を使用できますか？ <a class="header-anchor" href="#社内で-plannotator-を使用できますか" aria-label="Permalink to &quot;社内で Plannotator を使用できますか？&quot;">​</a></h3><p><strong>はい。</strong> BSL は、あなたと従業員、独立請負業者が社内開発、テスト、デプロイのために Plannotator を使用することを明示的に許可しています。制限は、<strong>第三者</strong>（従業員および請負業者以外）にサービスを提供するシナリオにのみ適用されます。</p><h3 id="plannotator-をベースに独自の製品を開発できますか" tabindex="-1">Plannotator をベースに独自の製品を開発できますか？ <a class="header-anchor" href="#plannotator-をベースに独自の製品を開発できますか" aria-label="Permalink to &quot;Plannotator をベースに独自の製品を開発できますか？&quot;">​</a></h3><p><strong>はい、ただし条件があります。</strong> 製品が以下の場合：</p><ul><li>社内ツール：✅ 許可</li><li>個人プロジェクト：✅ 許可</li><li>オープンソースプロジェクト：✅ 許可（BSL ライセンスを保持）</li><li>商用製品：❓ 「計画、コンテキスト、または承認サービス」に該当するかどうかの評価が必要</li></ul><h3 id="当社は-saas-プロバイダーですが、使用できますか" tabindex="-1">当社は SaaS プロバイダーですが、使用できますか？ <a class="header-anchor" href="#当社は-saas-プロバイダーですが、使用できますか" aria-label="Permalink to &quot;当社は SaaS プロバイダーですが、使用できますか？&quot;">​</a></h3><p><strong>商用ライセンスが必要です。</strong> SaaS 製品が Plannotator の機能を顧客に提供する場合（機能の一部としてであっても）、これは制限対象の商用サービスに該当し、商用ライセンスを購入する必要があります。</p><h3 id="_2030年以降、plannotator-をあらゆる目的に使用できますか" tabindex="-1">2030年以降、Plannotator をあらゆる目的に使用できますか？ <a class="header-anchor" href="#_2030年以降、plannotator-をあらゆる目的に使用できますか" aria-label="Permalink to &quot;2030年以降、Plannotator をあらゆる目的に使用できますか？&quot;">​</a></h3><p><strong>はい。</strong> 変更日以降、Plannotator は Apache 2.0 ライセンスを採用し、すべての商用制限が解除され、あらゆる目的に自由に使用できます。</p><h2 id="ライセンス全文" tabindex="-1">ライセンス全文 <a class="header-anchor" href="#ライセンス全文" aria-label="Permalink to &quot;ライセンス全文&quot;">​</a></h2><p>完全な Business Source License 1.1 のテキストは、プロジェクトルートディレクトリの <code>LICENSE</code> ファイルを参照してください。</p><h2 id="連絡先" tabindex="-1">連絡先 <a class="header-anchor" href="#連絡先" aria-label="Permalink to &quot;連絡先&quot;">​</a></h2><p>商用ライセンスやその他の質問については、以下にお問い合わせください：</p><ul><li><strong>ライセンサー</strong>：backnotprop</li><li><strong>プロジェクトリポジトリ</strong>：<a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="次のレッスンの予告" tabindex="-1">次のレッスンの予告 <a class="header-anchor" href="#次のレッスンの予告" aria-label="Permalink to &quot;次のレッスンの予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../../changelog/release-notes/">更新履歴</a></strong> を確認します。</p><p>以下の内容を学びます：</p><ul><li>Plannotator のバージョン履歴</li><li>各バージョンの新機能と改善点</li><li>重要なバグ修正</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>ライセンス表示</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>完全なライセンステキスト</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>重要情報</strong>：</p><ul><li>ライセンスの種類：Business Source License 1.1 (BSL)</li><li>著作権者：backnotprop (c) 2025</li><li>変更日：2030-01-01</li><li>変更後のライセンス：Apache License, Version 2.0</li><li>主な制限：計画、コンテキスト、または承認サービスへの使用禁止</li></ul></details>',47)])])}const b=a(n,[["render",e]]);export{u as __pageData,b as default};
